import "./accordion.css";

import { Accordion } from "radix-ui";
import { cn } from "tailwind-variants";

import { AccordionContext } from "./accordion.context";
import { accordionVariants } from "./accordion.variants";

export type AccordionRootProps = React.ComponentProps<typeof Accordion.Root>;

export const AccordionRoot = ({ className, ...props }: AccordionRootProps) => {
  const slots = accordionVariants();

  return (
    <AccordionContext value={{ slots }}>
      <Accordion.Root className={cn(slots.root(), className)} {...props} />
    </AccordionContext>
  );
};

import { Accordion } from "radix-ui";
import { cn } from "tailwind-variants";

import { useAccordionContext } from "./accordion.context";

export type AccordionItemProps = React.ComponentProps<typeof Accordion.Item>;

export const AccordionItem = ({ className, ...props }: AccordionItemProps) => {
  const { slots } = useAccordionContext();

  return <Accordion.Item className={cn(slots.item(), className)} {...props} />;
};

import { ChevronDown } from "lucide-react";
import { Accordion } from "radix-ui";
import { cn } from "tailwind-variants";

import { useAccordionContext } from "./accordion.context";

export type AccordionTriggerProps = React.ComponentProps<typeof Accordion.Trigger>;

export const AccordionTrigger = ({ children, className, ...props }: AccordionTriggerProps) => {
  const { slots } = useAccordionContext();

  return (
    <Accordion.Header className={slots.header()}>
      <Accordion.Trigger className={cn(slots.trigger(), className)} {...props}>
        {children}
        <ChevronDown aria-hidden className={slots.chevron()} />
      </Accordion.Trigger>
    </Accordion.Header>
  );
};

import { Accordion } from "radix-ui";
import { cn } from "tailwind-variants";

import { useAccordionContext } from "./accordion.context";

export type AccordionContentProps = React.ComponentProps<typeof Accordion.Content>;

export const AccordionContent = ({ children, className, ...props }: AccordionContentProps) => {
  const { slots } = useAccordionContext();

  return (
    <Accordion.Content className={cn(slots.content(), className)} {...props}>
      <div className={slots.contentText()}>{children}</div>
    </Accordion.Content>
  );
};

import { createContext, useContext } from "react";

import { accordionVariants } from "./accordion.variants";

export type AccordionContext = {
  slots: ReturnType<typeof accordionVariants>;
};

export const AccordionContext = createContext<AccordionContext | null>(null);

export const useAccordionContext = () => {
  const context = useContext(AccordionContext);
  if (!context) {
    throw new Error("useAccordionContext must be used within an Accordion");
  }
  return context;
};

/* eslint-disable perfectionist/sort-objects */

import { tv, type VariantProps } from "tailwind-variants";

export const accordionVariants = tv({
  slots: {
    root: "accordion",
    item: "accordion__item",
    header: "accordion__header",
    trigger: "accordion__trigger",
    chevron: "accordion__chevron",
    content: "accordion__content",
    contentText: "accordion__content-text",
  },
});

export type AccordionVariants = VariantProps<typeof accordionVariants>;

.accordion {
  @apply w-full;
}

.accordion__item {
  @apply border-border border-b;
}

.accordion__header {
  @apply flex;
}

.accordion__trigger {
  @apply flex flex-1 items-center justify-between py-4 text-sm font-medium transition-all;

  &:hover {
    @apply underline;
  }

  &[data-state="open"] > .accordion__chevron {
    @apply rotate-180;
  }
}

.accordion__chevron {
  @apply text-muted-foreground h-4 w-4 shrink-0 transition-transform duration-200;
}

.accordion__content {
  @apply overflow-hidden text-sm;

  &[data-state="open"] {
    @apply animate-accordion-down;
  }

  &[data-state="closed"] {
    @apply animate-accordion-up;
  }
}

.accordion__content-text {
  @apply pt-0 pb-4;
}

import { AccordionContent } from "./accordion-content";
import { AccordionItem } from "./accordion-item";
import { AccordionRoot } from "./accordion-root";
import { AccordionTrigger } from "./accordion-trigger";

export const Accordion = {
  Content: AccordionContent,
  Item: AccordionItem,
  Root: AccordionRoot,
  Trigger: AccordionTrigger,
};

export { AccordionContent, AccordionItem, AccordionRoot, AccordionTrigger };

export type { AccordionContentProps } from "./accordion-content";

export type { AccordionItemProps } from "./accordion-item";

export type { AccordionRootProps } from "./accordion-root";
export type { AccordionTriggerProps } from "./accordion-trigger";
export { AccordionContext, useAccordionContext } from "./accordion.context";
export { type AccordionVariants, accordionVariants } from "./accordion.variants";
